(1, 'home', 'hero_title', 'text', 'Find the Car That Fits You', '2026-04-20 18:15:57', '2026-05-02 06:07:40'),
(2, 'home', 'hero_subtitle', 'text', 'Verified listings. Trusted sellers. Great deals.', '2026-04-20 18:15:57', '2026-05-02 06:07:40'),
(3, 'home', 'hero_cta_text', 'text', 'View Listing', '2026-04-20 18:15:57', '2026-04-27 02:49:48'),
(4, 'home', 'hero_cta_href', 'text', '/inventory', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(5, 'home', 'home_search_label', 'text', 'search inventory', '2026-04-20 18:15:57', '2026-04-22 04:47:27'),
(6, 'home', 'recent_title', 'text', 'RECENT CARS', '2026-04-20 18:15:57', '2026-04-22 13:35:22'),
(7, 'home', 'recent_subtitle', 'textarea', 'Browse verified listings from trusted dealers and private sellers. Every vehicle is inspected, documented, and ready for purchase.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(8, 'home', 'hero_image', 'image', 'asset/images/media/slide-1-1777243596.jpg', '2026-04-20 18:15:57', '2026-04-27 02:46:45'),
(9, 'home', 'cta_left_image', 'image', 'asset/images/media/home-cta-left.jpg', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(10, 'home', 'cta_right_image', 'image', 'asset/images/media/home-cta-right.jpg', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(11, 'home', 'cta_left_title', 'text', 'LOOKING FOR A CAR?', '2026-04-20 18:15:57', '2026-04-22 04:48:53'),
(12, 'home', 'cta_left_body', 'textarea', 'Explore a wide range of cars—from budget-friendly options to premium luxury vehicles.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(13, 'home', 'cta_right_title', 'text', 'Sell Your Car', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(14, 'home', 'cta_right_body', 'textarea', 'List your car in minutes and connect with serious buyers. We help you price it right, promote it, and close faster.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(15, 'home', 'feat1_title', 'text', 'Extensive Vehicle Selection', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(16, 'home', 'feat1_body', 'textarea', 'Access a diverse range of vehicles—from reliable everyday cars to premium models—all in one place, carefully curated to match different budgets and preferences.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(17, 'home', 'feat2_title', 'text', 'Trusted by Real Buyers', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(18, 'home', 'feat2_body', 'textarea', 'New listings added daily, with a growing community of verified buyers and sellers who rely on our platform for safe and transparent transactions.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(19, 'home', 'feat3_title', 'text', 'Hassle-Free Ownership', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(20, 'home', 'feat3_body', 'textarea', 'From vehicle selection to inspection and delivery, we simplify the entire process—saving you time, money, and unnecessary stress.', '2026-04-20 18:15:57', '2026-05-02 06:18:05'),
(21, 'home', 'welcome_title', 'text', 'Real Cars. Real Process. Real Results.', '2026-04-20 18:15:57', '2026-05-02 12:56:37'),
(22, 'home', 'welcome_body', 'textarea', 'This short video shows how buyers successfully find and purchase vehicles through our platform, from first search to final handover.', '2026-04-20 18:15:57', '2026-05-02 12:56:37'),
(23, 'home', 'testimonial_name', 'text', 'Larry Uche', '2026-04-20 18:15:57', '2026-05-02 05:57:52'),
(24, 'home', 'testimonial_role', 'text', 'Car Enthusiast', '2026-04-20 18:15:57', '2026-05-02 05:57:52'),
(25, 'home', 'testimonial_quote', 'textarea', 'What stood out for me was the transparency. No hidden issues, no last-minute surprises. Everything was clearly explained, and the support team was responsive throughout.', '2026-04-20 18:15:57', '2026-05-02 12:58:03'),
(26, 'inventory', 'heading', 'text', 'Vehicles For Sale', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(27, 'inventory', 'intro', 'textarea', 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Inventory cards are dynamic and loaded from vehicle records.', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(28, 'inventory', 'fallback_image', 'image', 'asset/images/media/inventory-listing-fallback.jpg', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
(29, 'contact', 'heading', 'text', 'Contact Us', '2026-04-20 18:15:57', '2026-04-21 11:21:12'),
